var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"한 놈만 나타나서 다행이군. 하나 더 가세했으면 손 쓸 틈도 없이 당했겠어.","JPN":"1匹だけでよかった。もう1匹いたら打つ手もなくやられただろう。","ENG":"Thank goodness only one of them showed up. I wouldn't have stood a chance if there were any more.","TWN":"幸好只有一個傢伙。要是再加上一個，就一點辦法也沒有了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니! 수고하셨어요!","JPN":"リタお姉ちゃん！　お疲れ様でした！","ENG":"Rita! Great job!","TWN":"姐姐！辛苦了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호들갑 떨기엔 아직 일러, 꼬맹이.","JPN":"その台詞はまだ早い、ガキ。","ENG":"It's still too early to get excited, kid.","TWN":"還早呢，小鬼。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"갈 길이 머니까 체력을 아껴 둬. 지금은 네가......","JPN":"先が長いから体力を温存しておけ。今はお前が……","ENG":"Conserve your energy. We've got a long ways to go. Right now, you're...","TWN":"路還長，節省體力。現在你……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":" 응?","JPN":"ん？","ENG":" Huh?","TWN":" 嗯？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_DASH","text":{"KOREA":"왜 그래요, 언니?","JPN":"どうしました、リタお姉ちゃん？","ENG":"What's wrong, Rita?","TWN":"你怎麼了，姐姐？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_DASH","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_DASH","text":{"KOREA":"여기 보세요. 이번에는 생채기 하나 안 났어요.","JPN":"ほら、見てください。今回は傷一つなしで倒せたんですよ。","ENG":"Look. I didn't get a single scratch this time.","TWN":"看我，這次一個傷痕都沒有。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_DASH","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_DASH","text":{"KOREA":"헤헤, 저도 그새 실력이 쑥쑥 늘었나 봐요.","JPN":"へへ、私も実力がぐんぐん伸びてきたと思いませんか？","ENG":"Heh, I must have improved a lot.","TWN":"嘿嘿，看來我的實力也長進了不少呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_DASH","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너...... 잘도 내 앞에 다시 나타났구나.","JPN":"お前……よくもまた私の前に現れたな。","ENG":"You... You got some nerve showing up again.","TWN":"你……又是你。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_DASH","text":{"KOREA":"리타 언니......? 왜, 왜 그렇게 무서운 표정이에요?","JPN":"リタお姉ちゃん……？　な、なんでそんなに怖い顔を？","ENG":"Rita? W-why do you look so scary?","TWN":"麗塔姐姐……？為、為什麼表情這麼可怕？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_DASH","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_DASH","text":{"KOREA":"저 대시예요, 언니. 제 얼굴 잊어버린 거 아니죠?","JPN":"私はダッシュですよ。リタお姉ちゃん、私の顔を忘れちゃったんですか？","ENG":"It's me. Dash! You didn't forget my face, did you?","TWN":"我是黛西啊，姐姐。你不記得我了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_DASH","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"언니라고 부르지 마!","JPN":"軽々しく呼ぶな！","ENG":"Don't even try!","TWN":"別叫我姐姐！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"꼬맹이인 척 한다고 봐줄 생각 없어.","JPN":"ガキのふりをしても容赦はしない。","ENG":"I'm not going to cut you any slack, just because you pretend to be the kid.","TWN":"你即使裝成小鬼的樣子，我也不會手軟。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"이번에야말로...... 두 번 다시 내 앞에 나타날 수 없게 만들어 주지.","JPN":"今度こそ……二度と私の前に現れないようにしてやる。","ENG":"This time... I'll make sure you'll never come back again.","TWN":"這次……我要讓你再也不能出現在我面前。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니!","JPN":"リタお姉ちゃん！","ENG":"Rita!","TWN":"麗塔姐姐！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"......꼬맹이?","JPN":"……ガキ？","ENG":"... Kid?","TWN":"……小鬼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내, 내가 무슨 짓을......","JPN":"わ、私はなんてことを……","ENG":"W-what have I done?","TWN":"我、我究竟做了什麼……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네, 저 맞아요! 대시!","JPN":"はい、私ですよ！　ダッシュ！","ENG":"Yes, it's me! Dash!","TWN":"是、是我啊！黛西！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"오메르타가 갑자기 팔을 휘두르려고 해서 깜짝 놀랐어요.","JPN":"オメルタが急に腕を振り回そうとしてビックリしました。","ENG":"It scared the daylights out of me when Omerta suddenly lashed out.","TWN":"奧梅爾塔突然揮動胳膊，嚇了一跳。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나는...... 내 눈에는 방금 전까지 네가 그림자로......","JPN":"私は……私の目にはさっきまでお前がシャドウに見えて……","ENG":"You... You looked like a Shadow to me just now...","TWN":"我……剛剛我眼前，把你當成了暗影……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 왜 그러세요?","JPN":"どうしたんですか？","ENG":"What's wrong, Rita?","TWN":"姐姐，你怎麼了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대표님이 CRF가 떨어지면 카운터도 침식 증후군에 시달릴 수 있다고 했는데...... 혹시......","JPN":"代表の話ではCRFが落ちるとカウンターも侵食症候群になる可能性があるって……もしかして……","ENG":"The Boss said that even Counters can suffer from Corruption Syndrome if they deplete their CRF... Could it be...","TWN":"BOSS說CRF下降的話，制裁者也會出現被侵蝕症候群……難道……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......아냐. 침식 증후군은.","JPN":"……違う。侵食症候群じゃない。","ENG":"No... This isn't Corruption Syndrome.","TWN":"……不是侵蝕症候群。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 정신이 들자마자 갑자기 힘을 썼더니 좀 어지러웠을 뿐이야.","JPN":"そう。気が付いてからすぐに力を使ったせいで、めまいがしただけだ。","ENG":"Oh, I know. I must have overexerted myself and gotten all lightheaded.","TWN":"嗯，只是一醒過來就開始戰鬥，有點暈而已。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 정도는 목을 축이면 금방 괜찮아져.","JPN":"これぐらい、少し水分補給すればすぐ治る。","ENG":"Nothing that a little swig won't fix.","TWN":"我潤一潤喉嚨，馬上就會好了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L37_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗, 언니!","JPN":"あっ、リタお姉ちゃん！","ENG":"Rita, no!","TWN":"啊，姐姐！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"도시 하나를 잿더미로 만들 수 있는 괴물을 쓰러뜨렸어. 축배 정도는 들어 줘야지.","JPN":"都市一つを灰にできる怪物を倒したんだ。祝杯くらいはいいだろ。","ENG":"I just took down a monster that could level an entire city. A toast is in order.","TWN":"解決了能顛覆一個城市的怪物。怎麼也要舉杯慶祝一下啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그보다 꼬맹이, 맛있는 것 먹고 싶지 않아?","JPN":"……それよりガキ、美味しいものでも食べたくないか？","ENG":"By the way kid, how'd you like to eat something tasty?","TWN":"……不過，小鬼，你不想吃好吃的嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"맛있는 거요?","JPN":"美味しいもの？","ENG":"Tasty?","TWN":"好吃的？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_STARVE"},{"id":"L43_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"맛있는 게 뭔데요? 샌드위치? 토스트?","JPN":"例えば？　サンドイッチ？　トースト？","ENG":"Like what? Sandwiches? Toast?","TWN":"什麼好吃的？三明治？吐司？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그런 한 끼 식사 대용 말고.","JPN":"そんな軽食じゃなくて。","ENG":"No, not some lame brunch like that.","TWN":"不是那種東西。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤, 뭘까 생각했더니 더 배고파지네요.","JPN":"ヘヘッ、なんだろう。考えるだけでお腹が空いてきました。","ENG":"Heh heh, just thinking about it makes me hungry.","TWN":"嘿嘿，想著想著，肚子更餓了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그래도 전 언니랑 갈 수 있으면 어디든 좋아요!","JPN":"でも私はリタお姉ちゃんと一緒ならなんでもいいですよ！","ENG":"I'd be happy to go anywhere you take me!","TWN":"只要能跟姐姐在一起，哪裡都好！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"생일 지나면 말해. 내 단골 술집에 데려가 줄 테니까.","JPN":"誕生日が過ぎたら言うんだぞ。私の行きつけのバーに連れて行ってやる。","ENG":"Let me know when your birthday comes up. I'll take you to my favorite pub.","TWN":"你生日過了之後，我就帶你去我經常去的酒館。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"에이...... 언니는 그렇게 술이 좋아요?","JPN":"ええーリタお姉ちゃんはそんなにお酒が好きなんですか？","ENG":"Aw... Why do you like to drink so much?","TWN":"哎呀……姐姐這麼喜歡酒嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"술도 담배도 건강에 좋지 않고 비싸기만 하잖아요. 그 돈이면 감자가 몇 알인데요.","JPN":"お酒もタバコも健康に良くないのに高いだけじゃないですか。そのお金でジャガイモが何個買えるかわかります？","ENG":"Alcohol and tobacco are terrible for you. Plus, they're expensive too! You could buy a whole sack of potatoes with that kind of money.","TWN":"煙酒又貴，對身體又不好。用那個錢能買好多馬鈴薯呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"검소한 것도 나쁘진 않지.","JPN":"節約するのも悪くないだろう。","ENG":"Sure, it doesn't hurt to be frugal.","TWN":"節儉不是壞事。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하지만 너무 빈궁하게만 살면 영혼이 성장하지 못 해.","JPN":"でも貧窮しすぎると魂が成長できないんだ。","ENG":"But living like a miser isn't good for your soul either.","TWN":"但活得太過節儉，靈魂就無法成長。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그러니 네가 좋은 어른이 될 수 있도록. 내가 도와 줄게.","JPN":"……だからお前がいい大人になれるように、私が手伝ってやる。","ENG":"So I'll help you... become a better grown up.","TWN":"……所以，為了讓你能成為一個優秀的成年人。我來幫你。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"약속이야.","JPN":"約束だ。","ENG":"I promise.","TWN":"這是約定。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니?! 정신 차려요! 언니!","JPN":"リタお姉ちゃん！？　目を開けてください！","ENG":"Rita?! Wake up! Rita!","TWN":"姐姐？！醒醒！姐姐！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대표님, 도와 주세요! 언니가 또 쓰러졌어요!","JPN":"代表、助けてください！　リタお姉ちゃんがまた倒れたんです！","ENG":"Boss! Help! Rita passed out again!","TWN":"BOSS，幫幫忙！姐姐又暈倒了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};